  return (
    <div className="flex flex-col h-full space-y-4">

        {/* Modern Header Toolbar */}
        <div className="flex flex-col md:flex-row justify-between items-center bg-white/80 backdrop-blur-xl p-4 rounded-3xl border border-white/60 shadow-sm z-20">
            <div className="flex items-center gap-4 w-full md:w-auto mb-3 md:mb-0">
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2 pl-2">
                    <Mail className="text-pink-500" /> Inbox
                    <span className="bg-pink-50 text-pink-600 px-2 py-0.5 rounded-full text-xs font-bold border border-pink-100">{updates.length}</span>
                </h2>
            </div>

            <div className="flex items-center gap-2 w-full md:w-auto justify-between md:justify-end">
                {selectedIds.size > 0 ? (
                    <div className="flex items-center gap-2 animate-in slide-in-from-right-4 fade-in duration-300 w-full md:w-auto bg-slate-50 p-1.5 rounded-2xl border border-slate-100">
                        <span className="text-xs font-bold text-slate-500 px-2 whitespace-nowrap">{selectedIds.size} Selected</span>

                        <div className="h-4 w-px bg-slate-200 mx-1"></div>

                        <button 
                            onClick={handleBulkAcknowledge}
                            disabled={processing}
                            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white text-xs font-bold rounded-xl shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all hover:-translate-y-0.5"
                        >
                            {processing ? <Loader2 size={14} className="animate-spin"/> : <CheckCircle size={14}/>}
                            <span className="hidden sm:inline">Acknowledge All</span>
                        </button>

                        <button 
                            onClick={() => setDeleteModal({ isOpen: true, id: 'BULK' })}
                            className="flex items-center gap-2 px-3 py-2 bg-white text-red-500 border border-red-100 text-xs font-bold rounded-xl hover:bg-red-50 transition-all shadow-sm"
                            title="Delete Selected"
                        >
                            <Trash2 size={14}/>
                        </button>
                    </div>
                ) : (
                    <button 
                        onClick={() => setConfigModalOpen(true)}
                        className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all border ${autoConfig.enabled ? 'bg-green-50 text-green-700 border-green-200' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'}`}
