        </div>

        {/* Content Split */}
        <div className="flex-grow flex flex-col md:flex-row gap-6 overflow-hidden h-full">

            {/* LEFT: List Panel */}
            <div className="w-full md:w-1/3 min-w-[320px] bg-white/50 backdrop-blur-md rounded-3xl shadow-sm border border-white/60 flex flex-col overflow-hidden">
                {/* List Header Actions */}
                <div className="px-4 py-3 border-b border-white/50 flex justify-between items-center bg-white/40">
                    <button 
                        onClick={handleSelectAll} 
                        className={`flex items-center gap-2 text-xs font-bold transition-colors ${selectedIds.size === updates.length && updates.length > 0 ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
                        disabled={updates.length === 0}
                    >
                        {selectedIds.size > 0 && selectedIds.size === updates.length ? <CheckSquare size={16}/> : <Square size={16}/>}
                        Select All
                    </button>
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Recent Updates</span>
                </div>

                <div className="flex-grow overflow-y-auto p-3 space-y-2 custom-scrollbar">
                    {loading ? (
                        <div className="text-center py-10"><Loader2 className="animate-spin mx-auto text-pink-400"/></div>
                    ) : updates.length === 0 ? (
                        <div className="text-center py-20 text-slate-400 text-sm font-medium flex flex-col items-center">
                            <Mail size={32} className="mb-2 opacity-20"/>
