                                disabled={processing}
                                className="px-6 bg-white border-2 border-slate-100 text-slate-400 font-bold py-4 rounded-2xl hover:bg-red-50 hover:text-red-500 hover:border-red-200 transition-all shadow-sm"
                                title="Delete Request"
                            >
                                <Trash2 size={20} />
                            </button>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-slate-300 opacity-60">
                        <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mb-6 shadow-inner">
                            <Mail size={48} className="text-slate-200"/>
                        </div>
                        <p className="font-bold text-lg text-slate-400">Select an update to review</p>
                        <p className="text-xs text-slate-300 mt-2">AI will analyze the content automatically</p>
                    </div>
                )}
            </div>
        </div>

        {/* Delete Confirmation Modal */}
        {deleteModal.isOpen && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200" onClick={() => setDeleteModal({isOpen: false, id: null})}></div>
                <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm relative z-10 p-8 animate-in zoom-in-95 duration-200 border border-white/20">
                    <div className="text-center">
                        <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6 border-4 border-red-50 shadow-inner">
                            <Trash2 size={32} />
                        </div>
                        <h3 className="font-black text-2xl text-slate-800 mb-2">Delete {deleteModal.id === 'BULK' ? 'Selection' : 'Message'}?</h3>
                        <p className="text-sm text-slate-500 mb-8 leading-relaxed">
                            This action cannot be undone. The selected update(s) will be permanently removed from the inbox.
                        </p>
                        <div className="flex gap-3">
                            <button onClick={() => setDeleteModal({isOpen: false, id: null})} className="flex-1 py-3 bg-slate-100 text-slate-600 font-bold rounded-xl text-sm hover:bg-slate-200 transition-colors">Cancel</button>
                            <button onClick={confirmDelete} className="flex-1 py-3 bg-red-500 text-white font-bold rounded-xl text-sm hover:bg-red-600 shadow-lg shadow-red-200 transition-all">Yes, Delete</button>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Configuration Modal */}
        {configModalOpen && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200" onClick={() => setConfigModalOpen(false)}></div>
                <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md relative z-10 p-8 animate-in zoom-in-95 duration-200">
                    <div className="flex justify-between items-center mb-8">
                        <h3 className="text-xl font-black text-slate-800 flex items-center gap-2">
                            <Settings size={22} className="text-indigo-600" /> Automation Settings
                        </h3>
                        <button onClick={() => setConfigModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                    </div>

                    <div className="space-y-6">
                        <div className="bg-indigo-50 p-5 rounded-2xl text-xs font-medium text-indigo-800 leading-relaxed border border-indigo-100 flex gap-4">
                            <div className="bg-white p-2 rounded-lg h-fit shadow-sm text-indigo-600"><BrainCircuit size={18}/></div>
                            <p>
                                <strong>Auto-Acknowledgement:</strong> If enabled, the system will periodically process all incoming updates, apply AI analysis, update records, and send confirmation emails automatically without manual review.
                            </p>
                        </div>

                        <div className="flex items-center justify-between p-5 bg-slate-50 rounded-2xl border border-slate-200">
                            <span className="text-sm font-bold text-slate-700">Enable Auto-Processing</span>
                            <button 
                                onClick={() => setAutoConfig({...autoConfig, enabled: !autoConfig.enabled})}
                                className={`w-14 h-8 rounded-full transition-colors relative shadow-inner ${autoConfig.enabled ? 'bg-indigo-600' : 'bg-slate-300'}`}
                            >
                                <div className={`w-6 h-6 bg-white rounded-full absolute top-1 transition-all shadow-sm ${autoConfig.enabled ? 'left-7' : 'left-1'}`}></div>
                            </button>
                        </div>
                    </div>

                    <button 
                        onClick={saveAutoConfig}
                        className="w-full mt-8 py-3.5 bg-slate-900 hover:bg-black text-white font-bold rounded-xl shadow-lg transition-all"
                    >
                        Save Settings
                    </button>
                </div>
            </div>
        )}

    </div>
  );
};

