  alumni?: { first_name: string; last_name: string; program: string };
}

const InboxPage: React.FC = () => {
  const [updates, setUpdates] = useState<UserUpdate[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedUpdate, setSelectedUpdate] = useState<UserUpdate | null>(null);
  const [analysis, setAnalysis] = useState<UpdateAnalysisResult | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [processing, setProcessing] = useState(false);

  // Selection State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Modal States
  const [deleteModal, setDeleteModal] = useState<{ isOpen: boolean, id: string | null }>({ isOpen: false, id: null });
  const [configModalOpen, setConfigModalOpen] = useState(false);
  const [autoConfig, setAutoConfig] = useState({ enabled: false });

  useEffect(() => {
    fetchUpdates();
    loadAutoConfig();
  }, []);

  const loadAutoConfig = () => {
      const stored = localStorage.getItem('lu_inbox_auto_ack');
      if (stored) {
          const config = JSON.parse(stored);
          setAutoConfig(config);
          if (config.enabled) {
              handleAutoProcess();
          }
      }
  };

  const saveAutoConfig = () => {
      localStorage.setItem('lu_inbox_auto_ack', JSON.stringify(autoConfig));
      setConfigModalOpen(false);
      if (autoConfig.enabled) handleAutoProcess();
  };

  const fetchUpdates = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('user_updates')
        .select(`
          *,
          student:students(first_name, last_name, program),
          alumni:alumni(first_name, last_name, program)
        `)
        .order('submitted_at', { ascending: false });

      if (error) throw error;
      setUpdates(data as UserUpdate[]);
    } catch (e) {
      console.error("Error fetching updates:", e);
    } finally {
      setLoading(false);
    }
  };

  const handleSelectUpdate = async (update: UserUpdate) => {
    setSelectedUpdate(update);
    // Only re-analyze if it's a different update or no analysis exists
    if (selectedUpdate?.id !== update.id) {
        setAnalysis(null);
        setAnalyzing(true);
        try {
            const program = update.student?.program || update.alumni?.program || "Unknown";
            const result = await analyzeUserUpdate(update.update_text, program);
            setAnalysis(result);
        } catch (e) {
            console.error("AI Analysis failed:", e);
        } finally {
            setAnalyzing(false);
        }
    }
  };

  // --- PROCESSING LOGIC ---

  const processUpdateItem = async (update: UserUpdate) => {
      let result = analysis;
      // If batch processing or not the currently selected/analyzed item, re-analyze
      if (!result || selectedUpdate?.id !== update.id) {
          const program = update.student?.program || update.alumni?.program || "Unknown";
          result = await analyzeUserUpdate(update.update_text, program);
      }

      const userId = update.student_id || update.alumni_id;
      if (!userId) throw new Error("User ID not found linked to this update.");

      const idColumn = update.student_id ? 'student_id' : 'alumni_id';
      const respondentType = update.student_id ? 'student' : 'alumni';

      // 1. Create survey wrapper
      const { data: survey, error: surveyError } = await supabase
          .from('survey_responses')
          .insert([{
              respondent_type: respondentType,
              [idColumn]: userId,
              submitted_at: new Date().toISOString()
          }])
          .select()
          .single();

      if (surveyError) throw surveyError;

      // 2. Logic Branch
      if (result.intent === 'RETIRE' || result.intent === 'UNEMPLOYED') {
          // Archive old active records
          const { data: activeRecords } = await supabase
              .from('employment_information')
              .select('*')
              .in('employment_status', ['Employed', 'Self-employed'])
              .in('survey_response_id', (
                  await supabase.from('survey_responses').select('id').eq(idColumn, userId)
              ).data?.map(s => s.id) || []);

          if (activeRecords && activeRecords.length > 0) {
              const historyPayloads = activeRecords.map(r => ({
                  survey_response_id: r.survey_response_id,
                  employment_status: r.employment_status,
                  position: r.current_position,
                  company_name: r.company_name,
                  company_address: r.company_address,
                  job_level: r.current_job_level,
                  date_hired: r.date_hired,
                  business_name: r.business_name,
                  business_address: r.business_address,
                  business_type: r.business_type,
                  industry: r.industry,
                  job_alignment: r.job_alignment,
                  is_current_job: false
              }));
              await supabase.from('employment_history').insert(historyPayloads);
              await supabase.from('employment_information').delete().in('id', activeRecords.map(r => r.id));
          }

          // Insert New Status
          await supabase.from('employment_information').insert([{
              survey_response_id: survey.id,
              employment_status: result.employment_status,
              unemployed_reasons: result.unemployed_reasons,
              retirement_reason: result.retirement_reason,
          }]);

      } else {
          // Add/Update Job
          // Cleanup conflicting inactive statuses
          const { data: inactiveRecords } = await supabase
              .from('employment_information')
              .select('id')
              .in('employment_status', ['Unemployed', 'Retired'])
              .in('survey_response_id', (
                  await supabase.from('survey_responses').select('id').eq(idColumn, userId)
              ).data?.map(s => s.id) || []);

          if (inactiveRecords && inactiveRecords.length > 0) {
              await supabase.from('employment_information').delete().in('id', inactiveRecords.map(r => r.id));
          }

          await supabase.from('employment_information').insert([{
              survey_response_id: survey.id,
              employment_status: result.employment_status,
              company_name: result.company_name,
              current_position: result.current_position,
              company_address: result.company_address,
              employment_type: result.employment_type,
              industry: result.industry,
              job_alignment: result.job_alignment,
              business_name: result.employment_status === 'Self-employed' ? result.company_name : null,
              business_address: result.employment_status === 'Self-employed' ? result.company_address : null,
          }]);
      }

      // 3. Email
      const userName = (update.student || update.alumni) 
          ? `${update.student?.first_name || update.alumni?.first_name} ${update.student?.last_name || update.alumni?.last_name}`
          : "Alumni";

      await sendUpdateAcknowledgementEmail(
          userName,
          update.email,
          result.intent === 'ADD_JOB' ? 'New Job Added' : result.intent === 'RETIRE' ? 'Retirement Recorded' : 'Status Updated'
      );

      // 4. Delete
      await supabase.from('user_updates').delete().eq('id', update.id);
  };

  const handleApplySingle = async () => {
      if (!selectedUpdate) return;
      setProcessing(true);
      try {
          await processUpdateItem(selectedUpdate);
          alert("Update applied successfully!");
          setSelectedUpdate(null);
          setAnalysis(null);
          fetchUpdates();
      } catch (e: any) {
          alert("Failed to apply update: " + e.message);
      } finally {
          setProcessing(false);
      }
  };

  const handleBulkAcknowledge = async () => {
      if (selectedIds.size === 0) return;
      if (!window.confirm(`Are you sure you want to auto-process ${selectedIds.size} updates? This will apply AI-determined changes immediately.`)) return;

      setProcessing(true);
      const targets = updates.filter(u => selectedIds.has(u.id));
      let successCount = 0;

      for (const update of targets) {
          try {
              await processUpdateItem(update);
              successCount++;
          } catch (e) {
              console.error(`Failed to process update ${update.id}`, e);
          }
      }

      alert(`Processed ${successCount}/${targets.length} updates.`);
      setProcessing(false);
      setSelectedIds(new Set());
      fetchUpdates();
      setSelectedUpdate(null);
  };

  const handleAutoProcess = async () => {
      console.log("Auto-processing updates...");
  };

  // --- SELECTION ---

  const toggleSelect = (id: string) => {
      const newSet = new Set(selectedIds);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setSelectedIds(newSet);
  };

  const handleSelectAll = () => {
      if (selectedIds.size === updates.length) setSelectedIds(new Set());
      else setSelectedIds(new Set(updates.map(u => u.id)));
  };

  const handleCardDoubleClick = (e: React.MouseEvent, id: string) => {
      e.preventDefault();
      e.stopPropagation();
      toggleSelect(id);
  };

  const isSelectionMode = selectedIds.size > 0;

  // --- DELETE ---

  const handleDeleteClick = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      setDeleteModal({ isOpen: true, id });
  };

  const confirmDelete = async () => {
      if (!deleteModal.id) return;
      try {
          if (deleteModal.id === 'BULK') {
              const idsToDelete = Array.from(selectedIds);
              await supabase.from('user_updates').delete().in('id', idsToDelete);
              setSelectedIds(new Set());
              if (selectedUpdate && idsToDelete.includes(selectedUpdate.id)) {
                  setSelectedUpdate(null);
                  setAnalysis(null);
              }
          } else {
              await supabase.from('user_updates').delete().eq('id', deleteModal.id);
              if (selectedUpdate?.id === deleteModal.id) {
                  setSelectedUpdate(null);
                  setAnalysis(null);
              }
          }
          setDeleteModal({ isOpen: false, id: null });
          fetchUpdates();
      } catch (e) {
          alert("Failed to delete.");
      }
  };

  return (
    <div className="flex flex-col h-full space-y-4 p-2">

        {/* Modern Header Toolbar (Glass) */}
        <div className="flex flex-col md:flex-row justify-between items-center bg-white/60 backdrop-blur-2xl p-5 rounded-[2rem] border border-white/60 shadow-lg shadow-slate-200/50 z-20 transition-all hover:shadow-xl">
            <div className="flex items-center gap-4 w-full md:w-auto mb-3 md:mb-0">
                <div className="p-3 bg-gradient-to-tr from-pink-500 to-rose-500 rounded-2xl shadow-lg shadow-pink-200 text-white">
                    <Inbox size={24} />
                </div>
                <div>
                    <h2 className="text-xl font-black text-slate-800 tracking-tight">Update Inbox</h2>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">{updates.length} Pending Requests</p>
                </div>
            </div>

            <div className="flex items-center gap-3 w-full md:w-auto justify-between md:justify-end">
                {selectedIds.size > 0 ? (
                    <div className="flex items-center gap-3 animate-in slide-in-from-right-6 fade-in duration-300 w-full md:w-auto bg-white/50 p-1.5 pr-2 rounded-2xl border border-white/60 shadow-sm">
                        <span className="text-xs font-black text-slate-600 px-3 bg-slate-100/50 py-2 rounded-xl">{selectedIds.size} Selected</span>

                        <button 
                            onClick={handleBulkAcknowledge}
                            disabled={processing}
                            className="flex items-center gap-2 px-5 py-2.5 bg-slate-900 text-white text-xs font-bold rounded-xl shadow-lg hover:bg-indigo-700 transition-all hover:-translate-y-0.5 active:scale-95"
                        >
                            {processing ? <Loader2 size={14} className="animate-spin"/> : <CheckCircle size={14}/>}
                            <span className="hidden sm:inline">Approve All</span>
                        </button>

                        <button 
                            onClick={() => setDeleteModal({ isOpen: true, id: 'BULK' })}
                            className="p-2.5 bg-white text-red-500 border border-red-100 rounded-xl hover:bg-red-50 transition-all shadow-sm hover:shadow-red-100"
                            title="Delete Selected"
                        >
                            <Trash2 size={16}/>
                        </button>
                    </div>
                ) : (
                    <button 
                        onClick={() => setConfigModalOpen(true)}
                        className={`flex items-center gap-2 px-5 py-3 rounded-2xl text-xs font-bold transition-all border border-white/50 shadow-sm hover:shadow-md ${autoConfig.enabled ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-white/50 text-slate-500 hover:bg-white hover:text-slate-700'}`}
                    >
                        {autoConfig.enabled ? <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div> : <Settings size={16} />}
                        {autoConfig.enabled ? 'Auto-Processing On' : 'Configure Automation'}
                    </button>
                )}
            </div>
        </div>

        {/* Content Split */}
        <div className="flex-grow flex flex-col md:flex-row gap-6 overflow-hidden h-full">

            {/* LEFT: List Panel (Glass List) */}
            <div className="w-full md:w-1/3 min-w-[360px] bg-white/30 backdrop-blur-xl rounded-[2.5rem] shadow-2xl shadow-indigo-500/10 border border-white/50 flex flex-col overflow-hidden transition-all hover:bg-white/40 group/panel">

                {/* List Header */}
                <div className="px-6 py-5 border-b border-white/40 flex justify-between items-center bg-white/20 backdrop-blur-md z-10">
                    <span className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                       <Clock size={14}/> Recent
                    </span>
                    <button 
                        onClick={handleSelectAll} 
                        className={`flex items-center gap-2 text-xs font-bold px-3 py-1.5 rounded-lg transition-all ${selectedIds.size === updates.length && updates.length > 0 ? 'bg-indigo-100 text-indigo-700' : 'text-slate-500 hover:bg-white/50'}`}
                        disabled={updates.length === 0}
                    >
                        {selectedIds.size > 0 && selectedIds.size === updates.length ? <CheckSquare size={16}/> : <Square size={16}/>}
                        Select All
                    </button>
                </div>

                <div className="flex-grow overflow-y-auto p-4 space-y-3 custom-scrollbar relative">
                    {loading ? (
                        <div className="text-center py-20"><Loader2 className="animate-spin mx-auto text-indigo-400"/></div>
                    ) : updates.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-slate-400 opacity-60">
                            <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-4 shadow-inner">
                                <Inbox size={32} className="text-slate-300"/>
                            </div>
                            <p className="text-sm font-bold">All caught up!</p>
                            <p className="text-xs">No pending updates.</p>
                        </div>
                    ) : (
                        updates.map(update => {
                            const name = update.student 
                                ? `${update.student.first_name} ${update.student.last_name}`
                                : update.alumni 
                                    ? `${update.alumni.first_name} ${update.alumni.last_name}`
                                    : update.email;

                            const isSelected = selectedIds.has(update.id);
                            const isActive = selectedUpdate?.id === update.id;

                            return (
                                <div 
                                    key={update.id}
                                    onDoubleClick={(e) => handleCardDoubleClick(e, update.id)}
                                    onClick={() => handleSelectUpdate(update)}
                                    className={`relative p-5 rounded-[1.5rem] cursor-pointer transition-all duration-300 border group select-none
                                        ${isActive 
                                            ? 'bg-gradient-to-r from-indigo-50/90 to-white/90 border-indigo-200 shadow-md ring-1 ring-indigo-100 scale-[1.02]' 
                                            : 'bg-white/60 border-white/40 hover:bg-white/80 hover:shadow-lg hover:border-white/80 hover:scale-[1.01]'
                                        }
                                        ${isSelected ? 'ring-2 ring-indigo-500 bg-indigo-50/80' : ''}
                                    `}
                                >
                                    <div className="flex gap-4">
                                        {/* Selection Slot (Appears on Double Click / Mode) */}
                                        {isSelectionMode && (
                                            <div 
                                                className="shrink-0 flex items-center justify-center animate-in slide-in-from-left-2 fade-in duration-200"
                                                onClick={(e) => { e.stopPropagation(); toggleSelect(update.id); }}
                                            >
                                                <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${isSelected ? 'bg-indigo-500 border-indigo-500 text-white shadow-md shadow-indigo-300' : 'border-slate-300 bg-white hover:border-indigo-400'}`}>
                                                    {isSelected && <Check size={14} strokeWidth={4} />}
                                                </div>
                                            </div>
                                        )}

                                        <div className="flex-grow min-w-0">
                                            <div className="flex justify-between items-start mb-1.5">
                                                <h4 className={`font-bold text-sm truncate pr-8 ${isActive ? 'text-indigo-900' : 'text-slate-700'}`}>{name}</h4>
                                                <span className="text-[10px] font-bold text-slate-400 whitespace-nowrap bg-white/50 px-2 py-0.5 rounded-lg border border-white/60 shadow-sm">{new Date(update.submitted_at).toLocaleDateString()}</span>
                                            </div>
                                            <p className={`text-xs line-clamp-2 leading-relaxed ${isActive ? 'text-indigo-700/80' : 'text-slate-500'}`}>{update.update_text}</p>
                                        </div>
                                    </div>

                                    {/* Delete Button (Always Visible) */}
                                    <button 
                                        onClick={(e) => handleDeleteClick(update.id, e)}
                                        className="absolute top-4 right-4 p-2 text-slate-300 bg-white/50 hover:bg-red-50 hover:text-red-500 rounded-xl transition-all shadow-sm border border-transparent hover:border-red-100 hover:shadow-red-100"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            );
                        })
                    )}
                </div>
            </div>

            {/* RIGHT: Detail & Action Panel (Glass Card) */}
            <div className="flex-1 bg-white/60 backdrop-blur-2xl rounded-[2.5rem] shadow-2xl border border-white/60 p-8 flex flex-col relative overflow-hidden transition-all duration-500">

                {/* Background Decoration */}
                <div className="absolute -top-20 -right-20 w-96 h-96 bg-gradient-to-b from-indigo-100/40 to-transparent rounded-full blur-3xl pointer-events-none"></div>

                {selectedUpdate ? (
                    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 h-full flex flex-col relative z-10">
                        {/* User Info Header */}
                        <div className="flex items-center gap-6 mb-8 pb-6 border-b border-slate-200/50">
                            <div className="w-16 h-16 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-[1.2rem] flex items-center justify-center text-white font-black text-2xl shadow-lg shadow-indigo-200">
                                {(selectedUpdate.student?.first_name || selectedUpdate.alumni?.first_name || 'U')[0]}
                            </div>
                            <div>
                                <h2 className="text-3xl font-black text-slate-800 tracking-tight">
                                    {selectedUpdate.student ? `${selectedUpdate.student.first_name} ${selectedUpdate.student.last_name}` : selectedUpdate.alumni ? `${selectedUpdate.alumni.first_name} ${selectedUpdate.alumni.last_name}` : 'Unknown User'}
                                </h2>
                                <div className="flex flex-wrap items-center gap-3 mt-2">
                                    <span className="text-xs font-bold text-slate-500 flex items-center gap-1.5 bg-white/60 px-3 py-1.5 rounded-lg border border-white shadow-sm">
                                        <Mail size={12}/> {selectedUpdate.email} 
                                    </span>
                                    <span className="text-xs font-bold text-indigo-600 bg-indigo-50/80 px-3 py-1.5 rounded-lg border border-indigo-100/50 shadow-sm">
                                        {selectedUpdate.student?.program || selectedUpdate.alumni?.program || "Unknown Program"}
                                    </span>
                                </div>
                            </div>
                        </div>

                        {/* The Update Message Bubble */}
                        <div className="bg-gradient-to-br from-white to-slate-50 p-8 rounded-[2rem] border border-white shadow-lg shadow-slate-200/50 mb-8 relative group hover:shadow-xl transition-shadow">
                            <div className="absolute -top-4 -left-4 bg-white p-2 rounded-2xl shadow-md border border-slate-100 text-pink-500">
                                <MessageSquare size={24} fill="currentColor" className="opacity-90"/>
                            </div>
                            <p className="text-slate-700 italic text-xl leading-relaxed font-serif relative z-10">"{selectedUpdate.update_text}"</p>
                            <div className="absolute right-8 bottom-6 text-[10px] font-black text-slate-200 uppercase tracking-[0.2em]">Submitted Update</div>
                        </div>

                        {/* AI Analysis Section */}
                        <div className="flex-grow">
                            {analyzing ? (
                                <div className="h-full flex flex-col items-center justify-center text-slate-400 min-h-[200px] animate-in fade-in">
                                    <div className="relative w-20 h-20 mb-6">
                                        <div className="absolute inset-0 border-[6px] border-slate-100 rounded-full"></div>
                                        <div className="absolute inset-0 border-[6px] border-t-pink-500 border-transparent rounded-full animate-spin"></div>
                                        <Sparkles className="absolute inset-0 m-auto text-pink-300 animate-pulse" size={24} />
                                    </div>
                                    <p className="font-bold text-sm animate-pulse text-slate-500 uppercase tracking-widest">Analyzing Content...</p>
                                </div>
                            ) : analysis ? (
                                <div className="bg-white/80 backdrop-blur-xl rounded-[2rem] border border-white/60 p-8 shadow-xl shadow-indigo-500/5 relative overflow-hidden group hover:border-indigo-100 transition-colors">

                                    {/* Header Badge */}
                                    <div className="flex items-center justify-between mb-8 pb-4 border-b border-slate-100">
                                        <div className="flex items-center gap-3 text-indigo-900 font-black uppercase text-xs tracking-[0.15em]">
                                            <div className="p-1.5 bg-indigo-100 rounded-lg text-indigo-600"><BrainCircuit size={18}/></div>
                                            Proposed Action
                                        </div>
                                        <div className="flex gap-2">
                                            <span className="bg-indigo-600 text-white px-4 py-1.5 rounded-full text-xs font-bold shadow-lg shadow-indigo-200 border border-indigo-500">
                                                {analysis.intent}
                                            </span>
                                            {analysis.job_alignment && (
                                                <span className={`text-[10px] font-bold px-4 py-1.5 rounded-full border flex items-center gap-1.5 shadow-sm ${
                                                    analysis.job_alignment === 'Related' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' :
                                                    analysis.job_alignment === 'Non-Related' ? 'bg-amber-50 text-amber-700 border-amber-100' :
                                                    'bg-slate-50 text-slate-500 border-slate-200'
                                                }`}>
                                                    {analysis.job_alignment === 'Related' ? <Target size={12}/> : <AlertTriangle size={12}/>}
                                                    {analysis.job_alignment}
                                                </span>
                                            )}
                                        </div>
                                    </div>

                                    {/* Grid Data */}
                                    <div className="grid grid-cols-2 gap-8 relative z-10">
                                        <div className="space-y-2">
                                            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider block">New Status</span>
                                            <div className="font-bold text-slate-800 text-xl">{analysis.employment_status}</div>
                                        </div>

                                        {analysis.employment_type && (
                                            <div className="space-y-2">
                                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider block">Employment Type</span>
                                                <div className="font-bold text-slate-800 text-sm flex items-center gap-2 bg-slate-50 w-fit px-3 py-1 rounded-lg border border-slate-100">
                                                    <Clock size={14} className="text-slate-400"/> {analysis.employment_type}
                                                </div>
                                            </div>
                                        )}

                                        {(analysis.company_name || analysis.current_position) && (
                                            <>
                                            <div className="space-y-2">
                                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider block">Company / Business</span>
                                                <div className="font-bold text-slate-800 text-sm flex items-center gap-2">
                                                    <div className="p-1 bg-slate-100 rounded text-slate-500"><Building2 size={14}/></div> {analysis.company_name || 'N/A'}
                                                </div>
                                            </div>
                                            <div className="space-y-2">
                                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider block">Position</span>
                                                <div className="font-bold text-slate-800 text-sm flex items-center gap-2">
                                                    <div className="p-1 bg-slate-100 rounded text-slate-500"><Briefcase size={14}/></div> {analysis.current_position || 'N/A'}
                                                </div>
                                            </div>
                                            </>
                                        )}
                                        {analysis.company_address && (
                                            <div className="space-y-2 col-span-2">
                                                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider block">Location</span>
                                                <div className="font-bold text-slate-800 text-sm flex items-center gap-2">
                                                    <div className="p-1 bg-slate-100 rounded text-slate-500"><MapPin size={14}/></div> {analysis.company_address}
                                                </div>
                                            </div>
                                        )}
                                        {(analysis.unemployed_reasons || analysis.retirement_reason) && (
                                            <div className="col-span-2 space-y-2 bg-red-50/50 p-5 rounded-2xl border border-red-100/60 mt-2">
                                                <span className="text-[10px] font-bold text-red-400 uppercase tracking-wider block">Reason Provided</span>
                                                <div className="font-bold text-red-700 text-sm italic">
                                                    "{analysis.unemployed_reasons || analysis.retirement_reason}"
                                                </div>
                                            </div>
                                        )}
                                    </div>

                                    {/* Decorative BG */}
                                    <div className="absolute top-0 right-0 w-48 h-48 bg-gradient-to-b from-indigo-50 to-transparent rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 -z-0 opacity-50"></div>
                                </div>
                            ) : (
                                <div className="text-center text-red-400 mt-10 text-sm font-medium bg-red-50 p-6 rounded-2xl border border-red-100 border-dashed">
                                    Analysis Failed. Please try re-selecting the update.
                                </div>
                            )}
                        </div>

                        {/* Action Buttons */}
                        <div className="mt-8 flex gap-4 pt-8 border-t border-slate-100">
                            <button 
                                onClick={handleApplySingle}
                                disabled={processing || !analysis}
                                className="flex-1 bg-slate-900 text-white font-bold py-4 rounded-2xl shadow-xl shadow-slate-300 hover:bg-black hover:shadow-2xl hover:shadow-slate-400/50 transition-all flex items-center justify-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed group relative overflow-hidden"
                            >
                                <div className="absolute inset-0 bg-white/10 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                                {processing ? <Loader2 className="animate-spin" /> : (
                                    <div className="flex items-center gap-3 relative z-10">
                                        <div className="p-1 bg-emerald-500 rounded-full text-slate-900"><Check size={14} strokeWidth={4}/></div>
                                        <span>Acknowledge & Apply</span>
                                    </div>
                                )}
                            </button>
                            <button 
                                onClick={(e) => handleDeleteClick(selectedUpdate.id, e)}
                                disabled={processing}
                                className="px-6 bg-white border border-slate-200 text-slate-400 font-bold py-4 rounded-2xl hover:bg-red-50 hover:text-red-500 hover:border-red-200 transition-all shadow-sm flex items-center gap-2"
                                title="Delete Request"
                            >
                                <Trash2 size={20} />
                            </button>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-slate-300 opacity-60">
                        <div className="w-32 h-32 bg-gradient-to-b from-white to-slate-50 rounded-full flex items-center justify-center mb-8 shadow-inner border border-white">
                            <Mail size={64} className="text-slate-200"/>
                        </div>
                        <p className="font-black text-2xl text-slate-300 tracking-tight">Select an update</p>
                        <p className="text-sm text-slate-400 font-medium mt-2">AI will automatically analyze the content</p>
                    </div>
                )}
            </div>
        </div>

        {/* Delete Confirmation Modal */}
        {deleteModal.isOpen && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300" onClick={() => setDeleteModal({isOpen: false, id: null})}></div>
                <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-sm relative z-10 p-8 animate-in zoom-in-95 duration-200 border border-white/40 ring-1 ring-black/5">
                    <div className="text-center">
                        <div className="w-20 h-20 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner ring-4 ring-red-50">
                            <Trash2 size={36} />
                        </div>
                        <h3 className="font-black text-2xl text-slate-800 mb-3">Delete {deleteModal.id === 'BULK' ? 'Selection' : 'Message'}?</h3>
                        <p className="text-sm text-slate-500 mb-8 leading-relaxed font-medium">
                            This action cannot be undone. The update(s) will be permanently removed from the inbox.
                        </p>
                        <div className="flex gap-3">
                            <button onClick={() => setDeleteModal({isOpen: false, id: null})} className="flex-1 py-3.5 bg-slate-100 text-slate-600 font-bold rounded-2xl text-sm hover:bg-slate-200 transition-colors">Cancel</button>
                            <button onClick={confirmDelete} className="flex-1 py-3.5 bg-red-500 text-white font-bold rounded-2xl text-sm hover:bg-red-600 shadow-lg shadow-red-200 transition-all">Yes, Delete</button>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Configuration Modal */}
        {configModalOpen && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300" onClick={() => setConfigModalOpen(false)}></div>
                <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md relative z-10 p-8 animate-in zoom-in-95 duration-200 border border-white/40">
                    <div className="flex justify-between items-center mb-8">
                        <h3 className="text-xl font-black text-slate-800 flex items-center gap-3">
                            <div className="p-2 bg-indigo-100 rounded-xl text-indigo-600"><Settings size={20} /></div> Automation
                        </h3>
                        <button onClick={() => setConfigModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                    </div>

                    <div className="space-y-6">
                        <div className="bg-indigo-50/50 p-6 rounded-3xl text-xs font-medium text-indigo-800 leading-relaxed border border-indigo-100 flex gap-4">
                            <div className="bg-white p-2.5 rounded-xl h-fit shadow-sm text-indigo-600 border border-indigo-50"><BrainCircuit size={20}/></div>
                            <p className="mt-1">
                                <strong>Auto-Acknowledgement:</strong> If enabled, the system will periodically process all incoming updates, apply AI analysis, update records, and send confirmation emails automatically.
                            </p>
                        </div>

                        <div className="flex items-center justify-between p-6 bg-slate-50 rounded-3xl border border-slate-100">
                            <span className="text-sm font-bold text-slate-700">Enable Auto-Processing</span>
                            <button 
                                onClick={() => setAutoConfig({...autoConfig, enabled: !autoConfig.enabled})}
                                className={`w-14 h-8 rounded-full transition-colors relative shadow-inner ${autoConfig.enabled ? 'bg-indigo-600' : 'bg-slate-300'}`}
                            >
                                <div className={`w-6 h-6 bg-white rounded-full absolute top-1 transition-all shadow-sm ${autoConfig.enabled ? 'left-7' : 'left-1'}`}></div>
                            </button>
                        </div>
                    </div>

                    <button 
                        onClick={saveAutoConfig}
                        className="w-full mt-8 py-4 bg-slate-900 hover:bg-black text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95"
                    >
                        Save Settings
                    </button>
                </div>
            </div>
        )}

    </div>
  );
};

export default InboxPage;

import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabaseClient';
import { analyzeUserUpdate, UpdateAnalysisResult } from '../services/updatesAI';
import { sendUpdateAcknowledgementEmail } from '../services/emailService';
import { Loader2, Mail, CheckCircle, Trash2, ArrowRight, BrainCircuit, User, Calendar, Briefcase, MapPin, Building2, AlertTriangle, MessageSquare, CheckSquare, Square, Settings, X, Power, Target, Clock, Filter, Sparkles, Inbox, Check } from 'lucide-react';

interface UserUpdate {
  id: string;
  update_text: string;
  email: string;
  submitted_at: string;
  student_id?: string;
  alumni_id?: string;
  // Joined fields
  student?: { first_name: string; last_name: string; program: string };
  alumni?: { first_name: string; last_name: string; program: string };
}

const InboxPage: React.FC = () => {
  const [updates, setUpdates] = useState<UserUpdate[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedUpdate, setSelectedUpdate] = useState<UserUpdate | null>(null);
  const [analysis, setAnalysis] = useState<UpdateAnalysisResult | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [processing, setProcessing] = useState(false);

  // Selection State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Modal States
  const [deleteModal, setDeleteModal] = useState<{ isOpen: boolean, id: string | null }>({ isOpen: false, id: null });
  const [configModalOpen, setConfigModalOpen] = useState(false);
  const [autoConfig, setAutoConfig] = useState({ enabled: false });

  useEffect(() => {
    fetchUpdates();
    loadAutoConfig();
  }, []);

  const loadAutoConfig = () => {
      const stored = localStorage.getItem('lu_inbox_auto_ack');
      if (stored) {
          const config = JSON.parse(stored);
          setAutoConfig(config);
          if (config.enabled) {
              handleAutoProcess();
          }
      }
  };

  const saveAutoConfig = () => {
      localStorage.setItem('lu_inbox_auto_ack', JSON.stringify(autoConfig));
      setConfigModalOpen(false);
      if (autoConfig.enabled) handleAutoProcess();
  };

  const fetchUpdates = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('user_updates')
        .select(`
          *,
          student:students(first_name, last_name, program),
          alumni:alumni(first_name, last_name, program)
        `)
        .order('submitted_at', { ascending: false });

      if (error) throw error;
      setUpdates(data as UserUpdate[]);
    } catch (e) {
      console.error("Error fetching updates:", e);
    } finally {
      setLoading(false);
    }
  };

  const handleSelectUpdate = async (update: UserUpdate) => {
    setSelectedUpdate(update);
    // Only re-analyze if it's a different update or no analysis exists
    if (selectedUpdate?.id !== update.id) {
        setAnalysis(null);
        setAnalyzing(true);
        try {
            const program = update.student?.program || update.alumni?.program || "Unknown";
            const result = await analyzeUserUpdate(update.update_text, program);
            setAnalysis(result);
        } catch (e) {
            console.error("AI Analysis failed:", e);
        } finally {
            setAnalyzing(false);
        }
    }
  };

  // --- PROCESSING LOGIC ---

  const processUpdateItem = async (update: UserUpdate) => {
      let result = analysis;
      // If batch processing or not the currently selected/analyzed item, re-analyze
      if (!result || selectedUpdate?.id !== update.id) {
          const program = update.student?.program || update.alumni?.program || "Unknown";
          result = await analyzeUserUpdate(update.update_text, program);
      }

      const userId = update.student_id || update.alumni_id;
      if (!userId) throw new Error("User ID not found linked to this update.");

      const idColumn = update.student_id ? 'student_id' : 'alumni_id';
      const respondentType = update.student_id ? 'student' : 'alumni';

      // 1. Create survey wrapper
      const { data: survey, error: surveyError } = await supabase
          .from('survey_responses')
          .insert([{
              respondent_type: respondentType,
              [idColumn]: userId,
              submitted_at: new Date().toISOString()
          }])
          .select()
          .single();

      if (surveyError) throw surveyError;

      // 2. Logic Branch
      if (result.intent === 'RETIRE' || result.intent === 'UNEMPLOYED') {
          // Archive old active records
          const { data: activeRecords } = await supabase
              .from('employment_information')
              .select('*')
              .in('employment_status', ['Employed', 'Self-employed'])
              .in('survey_response_id', (
                  await supabase.from('survey_responses').select('id').eq(idColumn, userId)
              ).data?.map(s => s.id) || []);

          if (activeRecords && activeRecords.length > 0) {
              const historyPayloads = activeRecords.map(r => ({
                  survey_response_id: r.survey_response_id,
                  employment_status: r.employment_status,
                  position: r.current_position,
                  company_name: r.company_name,
                  company_address: r.company_address,
                  job_level: r.current_job_level,
                  date_hired: r.date_hired,
                  business_name: r.business_name,
                  business_address: r.business_address,
                  business_type: r.business_type,
                  industry: r.industry,
                  job_alignment: r.job_alignment,
                  is_current_job: false
              }));
              await supabase.from('employment_history').insert(historyPayloads);
              await supabase.from('employment_information').delete().in('id', activeRecords.map(r => r.id));
          }

          // Insert New Status
          await supabase.from('employment_information').insert([{
              survey_response_id: survey.id,
              employment_status: result.employment_status,
              unemployed_reasons: result.unemployed_reasons,
              retirement_reason: result.retirement_reason,
          }]);

      } else {
          // Add/Update Job
          // Cleanup conflicting inactive statuses
          const { data: inactiveRecords } = await supabase
              .from('employment_information')
              .select('id')
              .in('employment_status', ['Unemployed', 'Retired'])
              .in('survey_response_id', (
                  await supabase.from('survey_responses').select('id').eq(idColumn, userId)
              ).data?.map(s => s.id) || []);

          if (inactiveRecords && inactiveRecords.length > 0) {
              await supabase.from('employment_information').delete().in('id', inactiveRecords.map(r => r.id));
          }

          await supabase.from('employment_information').insert([{
              survey_response_id: survey.id,
              employment_status: result.employment_status,
              company_name: result.company_name,
              current_position: result.current_position,
              company_address: result.company_address,
              employment_type: result.employment_type,
              industry: result.industry,
              job_alignment: result.job_alignment,
              business_name: result.employment_status === 'Self-employed' ? result.company_name : null,
              business_address: result.employment_status === 'Self-employed' ? result.company_address : null,
          }]);
      }

      // 3. Email
      const userName = (update.student || update.alumni) 
          ? `${update.student?.first_name || update.alumni?.first_name} ${update.student?.last_name || update.alumni?.last_name}`
          : "Alumni";

      await sendUpdateAcknowledgementEmail(
          userName,
          update.email,
          result.intent === 'ADD_JOB' ? 'New Job Added' : result.intent === 'RETIRE' ? 'Retirement Recorded' : 'Status Updated'
      );

      // 4. Delete
      await supabase.from('user_updates').delete().eq('id', update.id);
  };

  const handleApplySingle = async () => {
      if (!selectedUpdate) return;
      setProcessing(true);
      try {
          await processUpdateItem(selectedUpdate);
          alert("Update applied successfully!");
          setSelectedUpdate(null);
          setAnalysis(null);
          fetchUpdates();
      } catch (e: any) {
          alert("Failed to apply update: " + e.message);
      } finally {
          setProcessing(false);
      }
  };

  const handleBulkAcknowledge = async () => {
      if (selectedIds.size === 0) return;
      if (!window.confirm(`Are you sure you want to auto-process ${selectedIds.size} updates? This will apply AI-determined changes immediately.`)) return;

      setProcessing(true);
      const targets = updates.filter(u => selectedIds.has(u.id));
      let successCount = 0;

      for (const update of targets) {
          try {
              await processUpdateItem(update);
              successCount++;
          } catch (e) {
              console.error(`Failed to process update ${update.id}`, e);
          }
      }

      alert(`Processed ${successCount}/${targets.length} updates.`);
      setProcessing(false);
      setSelectedIds(new Set());
      fetchUpdates();
      setSelectedUpdate(null);
  };

  const handleAutoProcess = async () => {
      console.log("Auto-processing updates...");
  };

  // --- SELECTION ---

  const toggleSelect = (id: string) => {
      const newSet = new Set(selectedIds);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setSelectedIds(newSet);
  };

  const handleSelectAll = () => {
      if (selectedIds.size === updates.length) setSelectedIds(new Set());
      else setSelectedIds(new Set(updates.map(u => u.id)));
  };

  const handleCardDoubleClick = (e: React.MouseEvent, id: string) => {
      e.preventDefault();
      e.stopPropagation();
      toggleSelect(id);
  };

  const isSelectionMode = selectedIds.size > 0;

  // --- DELETE ---

  const handleDeleteClick = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      setDeleteModal({ isOpen: true, id });
  };

  const confirmDelete = async () => {
      if (!deleteModal.id) return;
      try {
          if (deleteModal.id === 'BULK') {
              const idsToDelete = Array.from(selectedIds);
              await supabase.from('user_updates').delete().in('id', idsToDelete);
              setSelectedIds(new Set());
              if (selectedUpdate && idsToDelete.includes(selectedUpdate.id)) {
                  setSelectedUpdate(null);
                  setAnalysis(null);
              }
          } else {
              await supabase.from('user_updates').delete().eq('id', deleteModal.id);
              if (selectedUpdate?.id === deleteModal.id) {
                  setSelectedUpdate(null);
                  setAnalysis(null);
              }
          }
          setDeleteModal({ isOpen: false, id: null });
          fetchUpdates();
      } catch (e) {
          alert("Failed to delete.");
      }
  };

  return (
    <div className="flex flex-col h-full space-y-4 p-2">

        {/* Modern Header Toolbar (Glass - Pinkish) */}
        <div className="flex flex-col md:flex-row justify-between items-center bg-gradient-to-r from-pink-50/90 to-white/90 backdrop-blur-2xl p-5 rounded-[2rem] border border-white/60 shadow-lg shadow-pink-100/50 z-20 transition-all hover:shadow-xl">
            <div className="flex items-center gap-4 w-full md:w-auto mb-3 md:mb-0">
                <div className="p-3 bg-gradient-to-tr from-rose-500 to-pink-500 rounded-2xl shadow-lg shadow-pink-200 text-white">
                    <Inbox size={24} />
                </div>
                <div>
                    <h2 className="text-xl font-black text-slate-800 tracking-tight">Update Inbox</h2>
                    <p className="text-xs font-bold text-pink-400 uppercase tracking-wider">{updates.length} Pending Requests</p>
                </div>
            </div>

            <div className="flex items-center gap-3 w-full md:w-auto justify-between md:justify-end">
                {selectedIds.size > 0 ? (
                    <div className="flex items-center gap-3 animate-in slide-in-from-right-6 fade-in duration-300 w-full md:w-auto bg-white/50 p-1.5 pr-2 rounded-2xl border border-white/60 shadow-sm">
                        <span className="text-xs font-black text-slate-600 px-3 bg-slate-100/50 py-2 rounded-xl">{selectedIds.size} Selected</span>

                        <button 
                            onClick={handleBulkAcknowledge}
                            disabled={processing}
                            className="flex items-center gap-2 px-5 py-2.5 bg-slate-900 text-white text-xs font-bold rounded-xl shadow-lg hover:bg-indigo-700 transition-all hover:-translate-y-0.5 active:scale-95"
                        >
                            {processing ? <Loader2 size={14} className="animate-spin"/> : <CheckCircle size={14}/>}
                            <span className="hidden sm:inline">Approve All</span>
                        </button>

                        <button 
                            onClick={() => setDeleteModal({ isOpen: true, id: 'BULK' })}
                            className="p-2.5 bg-red-500 text-white border border-red-400 rounded-xl hover:bg-red-600 transition-all shadow-sm hover:shadow-red-200"
                            title="Delete Selected"
                        >
                            <Trash2 size={16}/>
                        </button>
                    </div>
                ) : (
                    <button 
                        onClick={() => setConfigModalOpen(true)}
                        className={`flex items-center gap-2 px-5 py-3 rounded-2xl text-xs font-bold transition-all border border-white/50 shadow-sm hover:shadow-md ${autoConfig.enabled ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-white/50 text-slate-500 hover:bg-white hover:text-slate-700'}`}
                    >
                        {autoConfig.enabled ? <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div> : <Settings size={16} />}
                        {autoConfig.enabled ? 'Auto-Processing On' : 'Configure Automation'}
                    </button>
                )}
            </div>
        </div>

        {/* Content Split */}
        <div className="flex-grow flex flex-col md:flex-row gap-6 overflow-hidden h-full">

            {/* LEFT: List Panel (Glass List) */}
            <div className="w-full md:w-1/3 min-w-[360px] bg-white/30 backdrop-blur-xl rounded-[2.5rem] shadow-2xl shadow-indigo-500/10 border border-white/50 flex flex-col overflow-hidden transition-all hover:bg-white/40 group/panel">

                {/* List Header */}
                <div className="px-6 py-5 border-b border-white/40 flex justify-between items-center bg-white/20 backdrop-blur-md z-10">
                    <span className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                       <Clock size={14}/> Recent
                    </span>
                    <button 
                        onClick={handleSelectAll} 
                        className={`flex items-center gap-2 text-xs font-bold px-3 py-1.5 rounded-lg transition-all ${selectedIds.size === updates.length && updates.length > 0 ? 'bg-indigo-100 text-indigo-700' : 'text-slate-500 hover:bg-white/50'}`}
                        disabled={updates.length === 0}
                    >
                        {selectedIds.size > 0 && selectedIds.size === updates.length ? <CheckSquare size={16}/> : <Square size={16}/>}
                        Select All
                    </button>
                </div>

                <div className="flex-grow overflow-y-auto p-4 space-y-3 custom-scrollbar relative">
                    {loading ? (
                        <div className="text-center py-20"><Loader2 className="animate-spin mx-auto text-indigo-400"/></div>
                    ) : updates.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-slate-400 opacity-60">
                            <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-4 shadow-inner">
                                <Inbox size={32} className="text-slate-300"/>
                            </div>
                            <p className="text-sm font-bold">All caught up!</p>
                            <p className="text-xs">No pending updates.</p>
                        </div>
                    ) : (
                        updates.map(update => {
                            const name = update.student 
                                ? `${update.student.first_name} ${update.student.last_name}`
                                : update.alumni 
                                    ? `${update.alumni.first_name} ${update.alumni.last_name}`
                                    : update.email;

                            const isSelected = selectedIds.has(update.id);
                            const isActive = selectedUpdate?.id === update.id;

                            return (
                                <div 
                                    key={update.id}
                                    onDoubleClick={(e) => handleCardDoubleClick(e, update.id)}
                                    onClick={() => handleSelectUpdate(update)}
                                    className={`relative p-5 pr-14 rounded-[1.5rem] cursor-pointer transition-all duration-300 border group select-none
                                        ${isActive 
                                            ? 'bg-gradient-to-r from-pink-50/80 to-white/90 border-pink-200 shadow-md ring-1 ring-pink-100 scale-[1.02]' 
                                            : 'bg-white/60 border-white/40 hover:bg-white/80 hover:shadow-lg hover:border-white/80 hover:scale-[1.01]'
                                        }
                                        ${isSelected ? 'ring-2 ring-indigo-500 bg-indigo-50/80' : ''}
                                    `}
                                >
                                    <div className="flex gap-4">
                                        {/* Selection Slot (Appears on Double Click / Mode) */}
                                        {isSelectionMode && (
                                            <div 
                                                className="shrink-0 flex items-center justify-center animate-in slide-in-from-left-2 fade-in duration-200"
                                                onClick={(e) => { e.stopPropagation(); toggleSelect(update.id); }}
                                            >
                                                <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${isSelected ? 'bg-indigo-500 border-indigo-500 text-white shadow-md shadow-indigo-300' : 'border-slate-300 bg-white hover:border-indigo-400'}`}>
                                                    {isSelected && <Check size={14} strokeWidth={4} />}
                                                </div>
                                            </div>
                                        )}

                                        <div className="flex-grow min-w-0">
                                            <div className="flex justify-between items-start mb-1.5">
                                                <h4 className={`font-bold text-sm truncate pr-2 ${isActive ? 'text-pink-700' : 'text-slate-700'}`}>{name}</h4>
                                                <span className="text-[10px] font-bold text-slate-400 whitespace-nowrap bg-white/50 px-2 py-0.5 rounded-lg border border-white/60 shadow-sm">{new Date(update.submitted_at).toLocaleDateString()}</span>
                                            </div>
                                            <p className={`text-xs line-clamp-2 leading-relaxed ${isActive ? 'text-pink-900/80' : 'text-slate-500'}`}>{update.update_text}</p>
                                        </div>
                                    </div>

                                    {/* Delete Button (Always Visible & Red) */}
                                    <button 
                                        onClick={(e) => handleDeleteClick(update.id, e)}
                                        className="absolute top-1/2 -translate-y-1/2 right-4 p-2 bg-white border border-red-100 text-red-500 rounded-xl shadow-sm hover:bg-red-500 hover:text-white transition-all z-20 group-hover:scale-110"
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            );
                        })
                    )}
                </div>
            </div>

            {/* RIGHT: Detail & Action Panel (Glass Card) */}
            <div className="flex-1 bg-white/60 backdrop-blur-2xl rounded-[2.5rem] shadow-2xl border border-white/60 p-0 flex flex-col relative overflow-hidden transition-all duration-500">

                {/* Background Decoration */}
                <div className="absolute -top-20 -right-20 w-96 h-96 bg-gradient-to-b from-indigo-100/40 to-transparent rounded-full blur-3xl pointer-events-none"></div>

                <div className="flex-grow overflow-y-auto p-8 pb-24 custom-scrollbar relative z-10">
                    {selectedUpdate ? (
                        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 flex flex-col min-h-full">
                            {/* User Info Header */}
                            <div className="flex items-center gap-6 mb-8 pb-6 border-b border-slate-200/50">
                                <div className="w-16 h-16 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-[1.2rem] flex items-center justify-center text-white font-black text-2xl shadow-lg shadow-indigo-200">
                                    {(selectedUpdate.student?.first_name || selectedUpdate.alumni?.first_name || 'U')[0]}
                                </div>
                                <div>
                                    <h2 className="text-3xl font-black text-slate-800 tracking-tight">
                                        {selectedUpdate.student ? `${selectedUpdate.student.first_name} ${selectedUpdate.student.last_name}` : selectedUpdate.alumni ? `${selectedUpdate.alumni.first_name} ${selectedUpdate.alumni.last_name}` : 'Unknown User'}
                                    </h2>
                                    <div className="flex flex-wrap items-center gap-3 mt-2">
                                        <span className="text-xs font-bold text-slate-500 flex items-center gap-1.5 bg-white/60 px-3 py-1.5 rounded-lg border border-white shadow-sm">
                                            <Mail size={12}/> {selectedUpdate.email} 
                                        </span>
                                        <span className="text-xs font-bold text-indigo-600 bg-indigo-50/80 px-3 py-1.5 rounded-lg border border-indigo-100/50 shadow-sm">
                                            {selectedUpdate.student?.program || selectedUpdate.alumni?.program || "Unknown Program"}
