                                                <div className="space-y-2">
                                                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider block">Position</span>
                                                    <div className="font-bold text-slate-800 text-sm flex items-center gap-2">
                                                        <div className="p-1 bg-white rounded text-slate-500 shadow-sm"><Briefcase size={14}/></div> {analysis.current_position || 'N/A'}
