                                onClick={() => setAutoConfig({...autoConfig, enabled: !autoConfig.enabled})}
                                className={`w-14 h-8 rounded-full transition-colors relative shadow-inner ${autoConfig.enabled ? 'bg-indigo-600' : 'bg-slate-300'}`}
                            >
                                <div className={`w-6 h-6 bg-white rounded-full absolute top-1 transition-all shadow-sm ${autoConfig.enabled ? 'left-7' : 'left-1'}`}></div>
                            </button>
