                    <div className="space-y-6">
                        <div className="bg-indigo-50/50 p-6 rounded-3xl text-xs font-medium text-indigo-800 leading-relaxed border border-indigo-100 flex gap-4">
                            <div className="bg-white p-2.5 rounded-xl h-fit shadow-sm text-indigo-600 border border-indigo-50"><BrainCircuit size={20}/></div>
                            <p className="mt-1">
                                <strong>Auto-Acknowledgement:</strong> If enabled, the system will periodically process all incoming updates, apply AI analysis, update records, and send confirmation emails automatically.
                            </p>
                        </div>

                        <div className="flex items-center justify-between p-6 bg-slate-50 rounded-3xl border border-slate-100">
                            <span className="text-sm font-bold text-slate-700">Enable Auto-Processing</span>
                            <button 
                                onClick={() => setAutoConfig({...autoConfig, enabled: !autoConfig.enabled})}
